UPDATE lessons SET code_lang='html', code_sample=E'<div class="box">Я блок</div>\n<style>\n  .box {\n    width: 200px;\n    background: lightblue;\n    padding: 20px;\n    border: 3px solid navy;\n    margin: 20px;\n  }\n</style>' WHERE course_id='html-css' AND position=6;
UPDATE lessons SET code_lang='html', code_sample=E'<p>Это мой текст для оформления</p>\n<style>\n  p {\n    font-size: 24px;\n    font-weight: bold;\n    text-align: center;\n    font-family: Arial, sans-serif;\n  }\n</style>' WHERE course_id='html-css' AND position=7;
UPDATE lessons SET code_lang='html', code_sample=E'<div class="row">\n  <div>1</div><div>2</div><div>3</div>\n</div>\n<style>\n  .row { display: flex; gap: 20px; justify-content: center; }\n  .row div { background: #6c5ce7; color: white; padding: 20px; }\n</style>' WHERE course_id='html-css' AND position=8;
UPDATE lessons SET code_lang='html', code_sample=E'<button>Нажми меня</button>\n<style>\n  button {\n    padding: 12px 24px;\n    background: #3498db;\n    color: white;\n    border: none;\n    border-radius: 8px;\n    cursor: pointer;\n    transition: 0.3s;\n  }\n  button:hover { background: #2980b9; }\n</style>' WHERE course_id='html-css' AND position=9;
UPDATE lessons SET code_lang='html', code_sample=E'<div class="card">Карточка</div>\n<style>\n  .card { width: 600px; background: lightgreen; padding: 20px; }\n  @media (max-width: 600px) {\n    .card { width: 100%; background: salmon; }\n  }\n</style>' WHERE course_id='html-css' AND position=10;
UPDATE lessons SET code_lang='html', code_sample=E'<div class="card">Красивая карточка</div>\n<style>\n  body { background: #ecf0f1; }\n  .card {\n    width: 250px;\n    padding: 30px;\n    background: white;\n    border-radius: 16px;\n    box-shadow: 0 8px 20px rgba(0,0,0,0.15);\n  }\n</style>' WHERE course_id='html-css' AND position=11;
UPDATE lessons SET code_lang='html', code_sample=E'<div class="card">\n  <h1>Алекс Кодов</h1>\n  <p>Начинающий разработчик</p>\n  <button>Связаться</button>\n</div>\n<style>\n  body { display: flex; justify-content: center; align-items: center; height: 100vh; background: #6c5ce7; }\n  .card { width: 300px; padding: 40px; background: white; border-radius: 20px; box-shadow: 0 10px 30px rgba(0,0,0,0.1); text-align: center; }\n  h1 { color: #2d3436; font-size: 28px; }\n  button { padding: 12px 28px; background: #6c5ce7; color: white; border: none; border-radius: 10px; cursor: pointer; }\n</style>' WHERE course_id='html-css' AND position=12;